mapper.sql:
select
,fdev.ext_dept_name AS pe_dept_name, fdev.ext_department_name AS pe_department, fdev.ext_team_name AS pe_team,
from pm_employee pe join (select * from td_train_employee_jurisdiction where id in (select max(id) from td_train_employee_jurisdiction group by employee_id)) ttej on pe.id = ttej.employee_id and pe.enabled_flag = 1 left outer join pm_employee_job pe_pej on pe.id = pe_pej.employee_id and pe_pej.job_main_flag = 1 and pe_pej.enabled_flag = 1 left outer join fnd_dept_ext_v fdev on pe_pej.dept_id = fdev.id and fdev.enabled_flag = 1 and fdev.deleted_flag = 0 left outer join fnd_job pe_pej_fj on pe_pej.job_id = pe_pej_fj.id and pe_pej_fj.enabled_flag = 1 and pe_pej_fj.deleted_flag = 1 where 1 = 1
and pe.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
and fdev.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
and tt.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}

mapper.delete:

delete from td_train_employee_jurisdiction
where employee_id = #{employeeId,jdbcType=BIGINT}
  and dept_id = #{deptId,jdbcType=BIGINT}

mapper.select:


select top 1 *
  from td_train_employee_jurisdiction
   where td_train_employee_jurisdiction.dept_id = #{deptId,jdbcType=BIGINT}
